import pandas as pd

orders = pd.DataFrame({
    'OrderId': [101, 102, 103],
    'CustomerId': [1, 2, 1],
    'Amount': [250, 450, 300]
})

customers = pd.DataFrame({
    'CustId': [1, 2, 3],
    'Name': ['Alice', 'Bob', 'Charlie']
})

result = pd.merge(orders, customers, left_on='CustomerId', right_on='CustId')
result = result.drop(columns=['CustId'])
print(result)

