import pandas as pd

students = pd.DataFrame({
    'StudentId': [1, 2, 3, 4],
    'Name': ['Alice', 'Bob', 'Charlie', 'Diana']
})

grades = pd.DataFrame({
    'StudentId': [1, 3, 5],
    'Grade': ['A', 'B', 'A']
})

result = pd.merge(students, grades, on='StudentId', how='inner')
print(result)

