exercises.solution:
import pandas as pd

products = pd.DataFrame({
    'ProductId': [1, 2, 3],
    'Name': ['Laptop', 'Phone', 'Tablet']
})

reviews = pd.DataFrame({
    'ProductId': [1, 3],
    'ReviewScore': [4.5, 3.8]
})

result = pd.merge(products, reviews, on='ProductId', how='left')
result['ReviewScore'] = result['ReviewScore'].fillna(0)
print(result)
